<script setup lang="ts">import{ref}from'vue';import{api}from'../api/client';const form=ref({course_id:1,chapter_title:'',resource_type:'lesson_plan',audience:'本科生',duration_minutes:45,requirements:''}),result=ref<any>(),error=ref('');async function run(){try{result.value=(await api.post('/lesson-resources/generate',form.value)).data}catch(e:any){error.value=e.message}}</script>
<template><div class="page"><h1>智能备课</h1><div class="card"><input type="number" v-model="form.course_id" placeholder="课程 ID"><input v-model="form.chapter_title" placeholder="章节名称"><select v-model="form.resource_type"><option value="lesson_plan">教案</option><option value="lecture">讲稿</option><option value="ppt_outline">PPT 大纲</option><option value="exercise">练习</option></select><input v-model="form.audience" placeholder="授课对象"><input type="number" v-model="form.duration_minutes"><textarea v-model="form.requirements" placeholder="补充要求"/><button @click="run">生成</button><p class="error">{{error}}</p></div><pre v-if="result" class="card answer">{{JSON.stringify(result,null,2)}}</pre></div></template>

